// // This module is designed to decrement a 4-bit binary counter on each rising edge of the clock signal and reset it to zero when the reset input is activated.
module top_module(
	input clk, reset,
	output reg [3:0] counter
);always@(posedge clk or posedge reset) begin
	if (reset) counter <= 4'd0;
	else counter <= counter + 1;
end


endmodule
